:root {
  /* Color system */
  --color-primary-gold: #D8B65A;
  --color-primary-ink: #333333;

  --color-secondary-blush: #FDF8F6;
  --color-secondary-lavender: #8A8FA8;

  --color-accent-peach: #D8906B;

  --color-neutral-white: #FFFFFF;
  --color-neutral-shell: #F3F1F4;
  --color-neutral-taupe: #C8C2BD;
  --color-neutral-ink: #222222;

  --color-success: #6BBF8C;
  --color-error: #D45B5B;
  --color-warning: #E7B15A;
  --color-info: #7A9ACB;

  /* Typography */
  --font-heading: 'League Spartan', Helvetica, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;
  --font-script: 'Great Vibes', 'Brush Script MT', cursive;

  --fs-h1: 3.5rem;   /* ~56px */
  --fs-h2: 2rem;     /* 32px */
  --fs-h3: 1.5rem;   /* 24px */
  --fs-body: 1rem;   /* 16px */
  --fs-small: 0.8125rem; /* 13px */

  --fw-light: 300;
  --fw-regular: 400;
  --fw-medium: 500;
  --fw-semibold: 600;
  --fw-bold: 700;

  --lh-tight: 1.2;
  --lh-normal: 1.5;
  --lh-relaxed: 1.75;

  /* Spacing scale (base 8px) */
  --space-1: 0.25rem;  /* 4px */
  --space-2: 0.5rem;   /* 8px */
  --space-3: 1rem;     /* 16px */
  --space-4: 1.5rem;   /* 24px */
  --space-5: 2rem;     /* 32px */
  --space-6: 3rem;     /* 48px */
  --space-7: 4rem;     /* 64px */

  --radius-soft: 4px;
  --radius-pill: 999px;

  --shadow-soft: 0 2px 8px rgba(0, 0, 0, 0.06);
  --border-hairline: 1px solid rgba(0, 0, 0, 0.06);

  --layout-max-width: 1200px;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--fs-body);
  line-height: var(--lh-normal);
  color: var(--color-neutral-ink);
  background-color: var(--color-neutral-white);
}

.site {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

.page-frame {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: 0 var(--space-6);
}

.site-header {
  background-color: var(--color-neutral-white);
}

/* Top header bar */

.header-bar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: var(--space-3);
  padding-bottom: var(--space-3);
  border-bottom: var(--border-hairline);
}

.header-brand {
  font-family: var(--font-script);
  font-size: 1.75rem;
  color: var(--color-primary-gold);
  text-decoration: none;
  white-space: nowrap;
}

.header-brand:hover,
.header-brand:focus-visible {
  text-decoration: none;
  color: var(--color-accent-peach);
}

/* Primary navigation */

.main-nav {
  flex: 1 1 auto;
  margin: 0 var(--space-4);
}

.main-nav-list {
  display: flex;
  gap: var(--space-3);
  list-style: none;
  padding: 0;
  margin: 0;
  justify-content: center;
  overflow-x: auto;
}

.main-nav-item a {
  font-family: var(--font-heading);
  font-size: 0.75rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  text-decoration: none;
  color: var(--color-primary-ink);
  padding-bottom: 0.25rem;
  white-space: nowrap;
  border-bottom: 2px solid transparent;
}

.main-nav-item a:hover,
.main-nav-item a:focus-visible {
  color: var(--color-accent-peach);
  border-bottom-color: var(--color-accent-peach);
}

/* User menu and avatar */

.user-menu {
  position: relative;
  flex: 0 0 auto;
}

.user-avatar {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  border-radius: 50%;
  border: 1px solid var(--color-neutral-taupe);
  background-color: var(--color-secondary-blush);
  color: var(--color-primary-ink);
  text-decoration: none;
  font-family: var(--font-heading);
  font-size: 0.75rem;
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

.user-avatar:hover,
.user-avatar:focus-visible {
  border-color: var(--color-primary-gold);
}

.user-initials {
  display: block;
}

.user-dropdown {
  position: absolute;
  right: 0;
  top: calc(100% + 0.5rem);
  min-width: 220px;
  background-color: var(--color-neutral-white);
  border-radius: var(--radius-soft);
  box-shadow: var(--shadow-soft);
  padding: var(--space-2) 0;
  list-style: none;
  margin: 0;
  display: none;
  z-index: 20;
}

.user-menu:hover .user-dropdown,
.user-menu:focus-within .user-dropdown {
  display: block;
}

.user-dropdown li a {
  display: block;
  padding: 0.5rem 1rem;
  font-size: 0.8125rem;
  font-family: var(--font-heading);
  letter-spacing: 0.12em;
  text-transform: uppercase;
  text-decoration: none;
  color: var(--color-primary-ink);
}

.user-dropdown li a:hover,
.user-dropdown li a:focus-visible {
  background-color: var(--color-secondary-blush);
  color: var(--color-accent-peach);
}

/* Hero area matching design */

.header-hero {
  background-color: var(--color-secondary-blush);
}

.header-hero-inner {
  display: grid;
  grid-template-columns: minmax(0, 1.1fr) minmax(0, 1.2fr);
  column-gap: var(--space-6);
  padding-top: var(--space-7);
  padding-bottom: var(--space-7);
  position: relative;
}

.hero-left {
  display: flex;
  align-items: center;
}

.hero-logo-lockup {
  text-decoration: none;
}

.hero-logo-mark {
  position: relative;
  width: 220px;
  height: 220px;
  margin: 0 auto;
}

.hero-logo-ring,
.hero-logo-ring-secondary {
  position: absolute;
  border-radius: 50%;
  border: 2px solid rgba(216, 182, 90, 0.8);
}

.hero-logo-ring {
  inset: 12%;
}

.hero-logo-ring-secondary {
  inset: 4%;
  border-color: rgba(216, 182, 90, 0.5);
}

.hero-logo-text-script {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-script);
  font-size: 2.4rem;
  color: var(--color-primary-gold);
  text-align: center;
}

.hero-logo-subtitle {
  position: absolute;
  left: 50%;
  bottom: 25%;
  transform: translateX(-50%);
  font-family: var(--font-heading);
  font-size: 0.75rem;
  letter-spacing: 0.24em;
  text-transform: uppercase;
  color: rgba(0, 0, 0, 0.45);
}

.hero-right {
  display: flex;
  align-items: center;
  justify-content: flex-start;
}

.hero-title-panel {
  background-color: var(--color-neutral-shell);
  padding: var(--space-5) var(--space-6);
  width: 100%;
}

.hero-kicker-row {
  display: flex;
  justify-content: flex-end;
  margin-bottom: var(--space-3);
}

.hero-kicker {
  font-family: var(--font-heading);
  font-size: 0.8125rem;
  letter-spacing: 0.3em;
  text-transform: uppercase;
  color: var(--color-secondary-lavender);
}

.hero-title {
  margin: 0 0 var(--space-3);
  font-family: var(--font-heading);
  font-size: var(--fs-h1);
  line-height: var(--lh-tight);
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--color-primary-ink);
}

.hero-subtitle {
  margin: 0;
  font-family: var(--font-heading);
  font-size: 0.875rem;
  letter-spacing: 0.26em;
  text-transform: uppercase;
  color: var(--color-accent-peach);
}

/* Tagline band */

.header-tagline-band {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-3);
  padding-top: var(--space-5);
  padding-bottom: var(--space-5);
}

.tagline-divider {
  flex: 1 1 0;
  height: 1px;
  background-color: rgba(0, 0, 0, 0.12);
}

.tagline-text {
  margin: 0;
  font-family: var(--font-heading);
  font-size: 0.875rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--color-primary-ink);
}

/* Main content area */

.site-content {
  flex: 1 0 auto;
  padding-top: var(--space-6);
  padding-bottom: var(--space-7);
}

/* Footer styling */

.site-footer {
  border-top: var(--border-hairline);
  background-color: var(--color-secondary-blush);
  padding-top: var(--space-6);
  padding-bottom: var(--space-4);
}

.footer-inner {
  display: grid;
  grid-template-columns: minmax(0, 1.5fr) minmax(0, 2fr);
  column-gap: var(--space-6);
  row-gap: var(--space-4);
  align-items: flex-start;
}

.footer-brand {
  max-width: 420px;
}

.footer-logo-mark {
  margin-bottom: var(--space-3);
}

.footer-logo-script {
  display: block;
  font-family: var(--font-script);
  font-size: 1.9rem;
  color: var(--color-primary-gold);
}

.footer-logo-subtitle {
  display: block;
  font-family: var(--font-heading);
  font-size: 0.75rem;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: rgba(0, 0, 0, 0.55);
}

.footer-copy {
  margin: 0;
  font-size: 0.9375rem;
  line-height: var(--lh-relaxed);
  color: rgba(0, 0, 0, 0.75);
}

.footer-nav {
  justify-self: flex-end;
}

.footer-nav-list {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: var(--space-2) var(--space-5);
  list-style: none;
  padding: 0;
  margin: 0;
}

.footer-nav-list li a {
  font-family: var(--font-heading);
  font-size: 0.8125rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  text-decoration: none;
  color: var(--color-primary-ink);
}

.footer-nav-list li a:hover,
.footer-nav-list li a:focus-visible {
  color: var(--color-accent-peach);
}

.footer-bottom {
  margin-top: var(--space-4);
  padding-top: var(--space-3);
  border-top: var(--border-hairline);
  text-align: center;
}

.footer-smallprint {
  margin: 0;
  font-size: var(--fs-small);
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: rgba(0, 0, 0, 0.55);
}

.footer-year {
  font-variant-numeric: tabular-nums;
}

/* Responsive adjustments */

@media (max-width: 1024px) {
  .page-frame {
    padding-left: var(--space-4);
    padding-right: var(--space-4);
  }

  .header-hero-inner {
    grid-template-columns: 1fr;
    row-gap: var(--space-6);
  }

  .hero-right {
    justify-content: center;
  }

  .hero-title-panel {
    padding: var(--space-5) var(--space-4);
  }

  .footer-inner {
    grid-template-columns: 1fr;
  }

  .footer-nav {
    justify-self: flex-start;
  }
}

@media (max-width: 768px) {
  .header-bar {
    flex-wrap: wrap;
    row-gap: var(--space-2);
  }

  .main-nav {
    order: 3;
    width: 100%;
    margin: var(--space-2) 0 0;
  }

  .main-nav-list {
    justify-content: flex-start;
  }

  .header-tagline-band {
    flex-direction: column;
    align-items: stretch;
  }

  .tagline-divider {
    display: none;
  }

  .tagline-text {
    text-align: center;
  }

  .hero-title {
    font-size: 2.5rem;
  }
}

@media (max-width: 480px) {
  .page-frame {
    padding-left: var(--space-3);
    padding-right: var(--space-3);
  }

  .hero-logo-mark {
    width: 180px;
    height: 180px;
  }

  .hero-title-panel {
    padding: var(--space-4) var(--space-3);
  }

  .main-nav-list {
    gap: var(--space-2);
  }
}
